
#import "JHDragView.h"

#define asconfig @""



@implementation JHDragView {
    UIView *statusDot;
}

- (instancetype)initWithFrame:(CGRect)frame {

    if (CGRectGetWidth(frame) <= 0 || CGRectGetHeight(frame) <= 0) {
        frame = CGRectMake([UIScreen mainScreen].bounds.size.width - 80 - 15, 
                         [UIScreen mainScreen].bounds.size.height * 0.3, 
                         80, 30);
    }

    self = [super initWithFrame:frame];
    if (self) {
        [self setupUI];
    }
    return self;
}

- (void)setupUI {

    self.layer.cornerRadius = self.frame.size.height / 2;
    self.clipsToBounds = YES;
    self.backgroundColor = [UIColor colorWithRed:0.12 green:0.12 blue:0.12 alpha:0.7]; 
    self.layer.borderWidth = 1.0;
    self.layer.borderColor = [UIColor colorWithWhite:1.0 alpha:0.2].CGColor;
    self.layer.shadowColor = [UIColor blackColor].CGColor;
    self.layer.shadowOffset = CGSizeMake(0, 2);
    self.layer.shadowOpacity = 0.3;


    UIImageView *iconView = [[UIImageView alloc] initWithFrame:CGRectMake(6, 5, 20, 20)];
    iconView.contentMode = UIViewContentModeScaleAspectFill;
    iconView.clipsToBounds = YES;
    iconView.layer.cornerRadius = 10;
    iconView.layer.borderWidth = 0.5;
    iconView.layer.borderColor = [UIColor colorWithWhite:1.0 alpha:0.3].CGColor;
    

    NSData *imageData = [[NSData alloc] initWithBase64EncodedString:asconfig options:0];
    if (imageData) {
        UIImage *originalImage = [UIImage imageWithData:imageData];
        UIGraphicsBeginImageContextWithOptions(iconView.bounds.size, NO, 0.0);
        [[UIBezierPath bezierPathWithOvalInRect:iconView.bounds] addClip];
        [originalImage drawInRect:iconView.bounds];
        iconView.image = UIGraphicsGetImageFromCurrentImageContext();
        UIGraphicsEndImageContext();
    } else {
        UIGraphicsBeginImageContextWithOptions(CGSizeMake(20, 20), NO, 0.0);
        [[UIColor whiteColor] setFill];
        [[UIBezierPath bezierPathWithOvalInRect:CGRectMake(0, 0, 20, 20)] fill];
        iconView.image = UIGraphicsGetImageFromCurrentImageContext();
        UIGraphicsEndImageContext();
    }
    [self addSubview:iconView];


    UIView *divider = [[UIView alloc] initWithFrame:CGRectMake(32, 5, 1, 20)];
    divider.backgroundColor = [UIColor colorWithWhite:1.0 alpha:0.2];
    [self addSubview:divider]; 
    UILabel *modLabel = [[UILabel alloc] initWithFrame:CGRectMake(38, 0, 37, 30)];
    modLabel.text = @"NEX";
    modLabel.textColor = [UIColor whiteColor];
    modLabel.font = [UIFont boldSystemFontOfSize:14];
    modLabel.textAlignment = NSTextAlignmentRight;
    [self addSubview:modLabel];


    statusDot = [[UIView alloc] initWithFrame:CGRectMake(30, 12, 6, 6)];
    statusDot.backgroundColor = [UIColor colorWithRed:0.0 green:0.8 blue:0.0 alpha:1.0];
    statusDot.layer.cornerRadius = 3;
    [self addSubview:statusDot];
}

#pragma mark - Touch Handling
- (void)touchesBegan:(NSSet<UITouch *> *)touches withEvent:(UIEvent *)event {
    [UIView animateWithDuration:0.1 animations:^{
        self.transform = CGAffineTransformMakeScale(0.95, 0.95);
    }];
}

- (void)touchesMoved:(NSSet<UITouch *> *)touches withEvent:(UIEvent *)event {
    UITouch *touch = [touches anyObject];
    CGPoint point = [touch locationInView:self.superview];
    self.center = point;
}

- (void)touchesEnded:(NSSet<UITouch *> *)touches withEvent:(UIEvent *)event {
    [UIView animateWithDuration:0.2 animations:^{
        self.transform = CGAffineTransformIdentity;
        [self snapToEdge];
    }];
}

- (void)touchesCancelled:(NSSet<UITouch *> *)touches withEvent:(UIEvent *)event {
    [self touchesEnded:touches withEvent:event];
}

#pragma mark - Snap to Edge
- (void)snapToEdge {
    CGFloat screenWidth = self.superview.bounds.size.width;
    CGFloat margin = 15.0;
    CGRect newFrame = self.frame;

    if (self.center.x <= screenWidth / 2) {
        newFrame.origin.x = margin;
    } else {
        newFrame.origin.x = screenWidth - self.frame.size.width - margin;
    }

    newFrame.origin.y = MAX(margin, MIN(newFrame.origin.y, self.superview.bounds.size.height - self.frame.size.height - margin));

    [UIView animateWithDuration:0.3 animations:^{
        self.frame = newFrame;
    }];
}

#pragma mark - Public Methods
- (void)showInView:(UIView *)view {
    [view addSubview:self];
    [view bringSubviewToFront:self];
    self.alpha = 0;
    self.transform = CGAffineTransformMakeScale(0.5, 0.5);

    [UIView animateWithDuration:0.4 animations:^{
        self.alpha = 1;
        self.transform = CGAffineTransformIdentity;
    }];
}

- (void)hide {
    [UIView animateWithDuration:0.3 animations:^{
        self.alpha = 0;
        self.transform = CGAffineTransformMakeScale(0.5, 0.5);
    } completion:^(BOOL finished) {
        [self removeFromSuperview];
    }];
}

@end